  ('aboriginal-6e11b43e-moex-00245', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-6ed013db', 'sub-aboriginal-6e11b43e-07', NULL, 'single_choice', '依司法院大法官之解釋，有關新聞自由之敘述，下列何者正確？', '["唯有報導政治事務之內容，才受新聞自由之憲法保障", "受新聞自由保障之客體，不包括娛樂與運動新聞", "受新聞自由保障之客體，僅限於報導最終呈現之內容", "受新聞自由保障之主體，包括從事新聞工作之個人與事業在內"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00246', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-6ed013db', 'sub-aboriginal-6e11b43e-07', NULL, 'single_choice', '依憲法增修條文規定，關於立法委員之不受逮捕特權，下列敘述何者錯誤？', '["僅限於會期中，始得主張此項特權", "僅限於立法院內之行為，始得主張此項特權", "若為現行犯，則不得主張此項特權", "經立法院許可，仍得逮捕立法委員"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00247', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-6ed013db', 'sub-aboriginal-6e11b43e-07', NULL, 'single_choice', '依憲法及增修條文規定，下列有關正、副總統缺位之敘述，何者錯誤？', '["總統缺位時，由副總統繼任至原任期屆滿為止", "副總統缺位時，總統應經行政院會議之議決，提名候選人", "行政院院長代行總統職權，其期限不得逾3個月", "正、副總統皆缺位時，由自由地區全體人民直選，補選出繼任者，繼任至原任期屆滿為止"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00248', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-6ed013db', 'sub-aboriginal-6e11b43e-07', NULL, 'single_choice', '下列何者不屬於國家賠償責任範圍？', '["警察駕駛警車巡邏時撞傷人民", "人民駕車掉入高速公路路面坑洞而受傷", "人民所有之既成道路因提供公眾通行而無法自由使用", "人民因為公務員怠於執行職務而死亡"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00249', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-6ed013db', 'sub-aboriginal-6e11b43e-07', NULL, 'single_choice', '有關憲法之施行及效力，下列敘述何者正確？', '["憲法增修條文，應先經大法官審查確定無違憲後，方得公布施行", "憲法增修條文，係由總統令公布實施", "法律與憲法是否牴觸，應由總統召集院際調解委員會確認決定", "命令與憲法是否牴觸，應由代表民意的立法機關確認決定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00250', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-6ed013db', 'sub-aboriginal-6e11b43e-07', NULL, 'single_choice', '行政機關對於法律規定之解釋，如增加法律所無之限制，逾越母法之規定，則與憲法第23條何種原則 之意旨不符？', '["法律不溯及既往原則", "平等原則", "信賴保護原則", "法律保留原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00251', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-6ed013db', 'sub-aboriginal-6e11b43e-07', NULL, 'single_choice', '關於憲法第8條人身自由之保障主體，下列敘述何者正確？', '["憲法第8條之人身自由為國民權，僅保障我國國民", "憲法第8條之人身自由，除保障我國國民，亦保障外國人", "憲法第8條之人身自由，亦保障外國人，但以我國之邦交國國民為限", "憲法第8條之人身自由，亦保障外國人，但以持有我國永久居留證者為限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL)
